const ASSETS = {"/index.html":{"type":"text/html; charset=utf-8","body":"<!DOCTYPE html>\n<html lang=\"fr\">\n<head>\n<meta charset=\"UTF-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1, viewport-fit=cover, user-scalable=no\" />\n<title>Marées</title>\n<meta name=\"theme-color\" content=\"#04264c\" />\n<meta name=\"apple-mobile-web-app-capable\" content=\"yes\" />\n<meta name=\"apple-mobile-web-app-status-bar-style\" content=\"black-translucent\" />\n<meta name=\"apple-mobile-web-app-title\" content=\"Marées\" />\n<link rel=\"apple-touch-icon\" href=\"icon-180.png\" />\n<link rel=\"icon\" href=\"icon-180.png\" />\n<link rel=\"manifest\" href=\"manifest.webmanifest\" />\n<style>\n  :root {\n    --top: #0a6ab0; --bottom: #04264c;\n    --high: #66d9ff; --low: #fbe6b4;\n    --card: rgba(255,255,255,.10); --stroke: rgba(255,255,255,.14);\n    --txt: #fff; --faint: rgba(255,255,255,.75); --fainter: rgba(255,255,255,.5);\n  }\n  * { box-sizing: border-box; -webkit-tap-highlight-color: transparent; }\n  html { margin: 0; background: var(--bottom); }\n  body { margin: 0; }\n  body {\n    font-family: -apple-system, BlinkMacSystemFont, \"SF Pro Text\", \"Segoe UI\", Roboto, sans-serif;\n    color: var(--txt);\n    background: linear-gradient(180deg, var(--top), var(--bottom) 70%, var(--bottom));\n    min-height: 100dvh;\n    padding: max(16px, env(safe-area-inset-top)) 16px calc(24px + env(safe-area-inset-bottom));\n    -webkit-font-smoothing: antialiased;\n  }\n  .wrap { max-width: 640px; margin: 0 auto; }\n\n  header { display: flex; align-items: center; justify-content: space-between; margin: 4px 4px 18px; }\n  h1 { font-size: 34px; font-weight: 800; letter-spacing: -.02em; margin: 0; }\n  .port-btn {\n    display: inline-flex; align-items: center; gap: 6px; margin-top: 4px;\n    background: none; border: 0; color: var(--faint); font-size: 15px; font-weight: 500;\n    font-family: inherit; padding: 0; cursor: pointer;\n  }\n  .port-btn svg { width: 15px; height: 15px; }\n  .spinner { width: 22px; height: 22px; border: 2.5px solid rgba(255,255,255,.25);\n    border-top-color: #fff; border-radius: 50%; animation: spin .8s linear infinite; }\n  @keyframes spin { to { transform: rotate(360deg); } }\n\n  .card {\n    background: var(--card); border: 1px solid var(--stroke);\n    border-radius: 28px; padding: 20px; margin-bottom: 16px;\n    backdrop-filter: blur(20px) saturate(140%); -webkit-backdrop-filter: blur(20px) saturate(140%);\n    box-shadow: 0 14px 40px rgba(0,0,0,.18);\n  }\n  .hero { background: linear-gradient(160deg, rgba(102,217,255,.30), rgba(10,106,176,.35)); }\n\n  .trend { font-size: 15px; font-weight: 600; color: var(--faint); display: flex; align-items: center; gap: 6px; }\n  .now-row { display: flex; align-items: flex-end; justify-content: space-between; margin-top: 10px; }\n  .height { font-size: 64px; font-weight: 800; letter-spacing: -.03em; line-height: 1;\n    font-variant-numeric: tabular-nums; }\n  .height small { font-size: 24px; font-weight: 600; color: var(--faint); }\n  .coef { text-align: center; }\n  .coef b { display: block; font-size: 30px; font-weight: 800; }\n  .coef span { font-size: 12px; color: var(--faint); }\n\n  .divider { height: 1px; background: rgba(255,255,255,.18); margin: 16px 0; }\n  .next { display: flex; align-items: center; gap: 12px; }\n  .next .ic { width: 34px; height: 34px; flex: 0 0 34px; }\n  .next .lbl { font-size: 13px; color: var(--faint); }\n  .next .val { font-size: 17px; font-weight: 700; }\n  .pill { margin-left: auto; background: rgba(255,255,255,.18); border-radius: 999px;\n    padding: 6px 12px; font-size: 14px; font-weight: 600; white-space: nowrap; }\n\n  .card h2 { font-size: 17px; font-weight: 700; margin: 0 0 12px; }\n  .row { display: flex; align-items: center; gap: 12px; padding: 7px 0; }\n  .row .ic { width: 22px; height: 22px; flex: 0 0 22px; }\n  .row .type { font-size: 15px; color: var(--faint); }\n  .row .rcoef { margin-left: auto; font-size: 12px; font-weight: 600; color: var(--faint);\n    background: rgba(255,255,255,.12); border-radius: 999px; padding: 3px 8px; }\n  .row .h { width: 66px; text-align: right; font-size: 15px; color: var(--faint); font-variant-numeric: tabular-nums; }\n  .row .t { width: 52px; text-align: right; font-size: 15px; font-weight: 700; font-variant-numeric: tabular-nums; }\n  .row.past { opacity: .45; }\n  .daygroup + .daygroup { border-top: 1px solid rgba(255,255,255,.12); margin-top: 8px; padding-top: 8px; }\n  .dayname { font-size: 14px; font-weight: 600; color: var(--faint); margin: 4px 0; }\n\n  svg.chart { width: 100%; height: 200px; display: block; }\n\n  /* Feuille de recherche */\n  .sheet-bg { position: fixed; inset: 0; background: rgba(0,0,0,.4); backdrop-filter: blur(6px);\n    display: none; align-items: flex-end; z-index: 20; }\n  .sheet-bg.open { display: flex; }\n  .sheet { background: #0b3358; width: 100%; max-height: 82dvh; border-radius: 24px 24px 0 0;\n    padding: 14px 16px calc(20px + env(safe-area-inset-bottom)); overflow-y: auto;\n    box-shadow: 0 -10px 40px rgba(0,0,0,.4); }\n  .sheet .grab { width: 40px; height: 5px; background: rgba(255,255,255,.3); border-radius: 3px; margin: 4px auto 12px; }\n  .search-in { width: 100%; font-size: 17px; font-family: inherit; color: #fff;\n    background: rgba(255,255,255,.12); border: 1px solid var(--stroke); border-radius: 14px;\n    padding: 12px 14px; outline: none; }\n  .search-in::placeholder { color: var(--fainter); }\n  .result { display: flex; align-items: center; gap: 12px; padding: 14px 6px; width: 100%;\n    background: none; border: 0; border-bottom: 1px solid rgba(255,255,255,.08); color: #fff;\n    font-family: inherit; font-size: 16px; text-align: left; cursor: pointer; }\n  .result small { display: block; color: var(--faint); font-size: 12px; }\n\n  .state { text-align: center; color: var(--faint); padding: 60px 20px; }\n  .state svg { width: 40px; height: 40px; margin-bottom: 12px; }\n  .btn { font-family: inherit; font-size: 16px; font-weight: 600; color: #fff;\n    background: rgba(255,255,255,.18); border: 0; border-radius: 14px; padding: 12px 20px; margin-top: 14px; cursor: pointer; }\n</style>\n</head>\n<body>\n<div class=\"wrap\">\n  <header>\n    <div>\n      <h1>Marées</h1>\n      <button class=\"port-btn\" id=\"portBtn\">\n        <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M12 21s-7-5.6-7-11a7 7 0 0 1 14 0c0 5.4-7 11-7 11z\"/><circle cx=\"12\" cy=\"10\" r=\"2.5\"/></svg>\n        <span id=\"portName\">…</span>\n        <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\" style=\"width:12px;height:12px\"><path d=\"M6 9l6 6 6-6\"/></svg>\n      </button>\n    </div>\n    <div id=\"headSpin\"></div>\n  </header>\n  <main id=\"content\"><div class=\"state\"><div class=\"spinner\" style=\"margin:0 auto\"></div></div></main>\n</div>\n\n<div class=\"sheet-bg\" id=\"sheetBg\">\n  <div class=\"sheet\" id=\"sheet\">\n    <div class=\"grab\"></div>\n    <input class=\"search-in\" id=\"searchIn\" placeholder=\"Saint-Malo, Brest, La Rochelle…\" autocomplete=\"off\" />\n    <div id=\"results\"></div>\n  </div>\n</div>\n\n<script>\n// Base de l'API. Sous le Cloudflare Worker, tout est same-origin → \"/api\".\nconst API_BASE = (window.MAREE_API_BASE ?? \"/api\");\nconst DEFAULT_PORT = { id: 17, nom: \"Saint-Malo\", lat: 48.6539, lon: -2.01563, time_zone: \"Europe/Paris\" };\n\nconst $ = (s) => document.querySelector(s);\nlet state = { port: loadPort(), tides: [], loading: false, error: null };\nlet tick = null;\n\nfunction loadPort() {\n  try { return JSON.parse(localStorage.getItem(\"maree.port\")) || DEFAULT_PORT; }\n  catch { return DEFAULT_PORT; }\n}\nfunction savePort(p) { localStorage.setItem(\"maree.port\", JSON.stringify(p)); }\n\n// ---- Réseau\nasync function apiSearch(q) {\n  const r = await fetch(`${API_BASE}/search?q=${encodeURIComponent(q)}`);\n  if (!r.ok) throw new Error(\"http \" + r.status);\n  const j = await r.json();\n  return (j.contenu || []).filter((p) => p.presence_maree !== false);\n}\nasync function apiTides(lat, lon) {\n  const r = await fetch(`${API_BASE}/tides?lat=${lat}&lon=${lon}`);\n  if (!r.ok) throw new Error(\"http \" + r.status);\n  const j = await r.json();\n  const days = (j.contenu && j.contenu.marees) || [];\n  const out = [];\n  for (const d of days) for (const e of (d.etales || [])) {\n    out.push({\n      date: new Date(e.datetime),\n      hhmm: String(e.datetime).slice(11, 16),\n      type: e.type_etale, hauteur: e.hauteur, coef: e.coef,\n    });\n  }\n  out.sort((a, b) => a.date - b.date);\n  return out;\n}\n\n// ---- Calculs\nfunction surrounding(now, t) {\n  let prev = null, next = null;\n  for (const x of t) { if (x.date <= now) prev = x; else { next = x; break; } }\n  return { prev, next };\n}\nfunction heightNow(now, t) {\n  const { prev, next } = surrounding(now, t);\n  if (!prev || !next) return null;\n  const span = next.date - prev.date; if (span <= 0) return prev.hauteur;\n  const k = (now - prev.date) / span;\n  return prev.hauteur + (next.hauteur - prev.hauteur) * (1 - Math.cos(Math.PI * k)) / 2;\n}\nfunction coefNow(now, t) {\n  const { next } = surrounding(now, t);\n  if (next && next.type === \"PM\" && next.coef != null) return next.coef;\n  const highs = t.filter((x) => x.type === \"PM\" && x.coef != null);\n  if (!highs.length) return null;\n  highs.sort((a, b) => Math.abs(a.date - now) - Math.abs(b.date - now));\n  return highs[0].coef;\n}\nconst isHigh = (x) => x.type === \"PM\";\nconst metres = (h) => h == null ? \"—\" : h.toFixed(2).replace(\".\", \",\");\nfunction dur(ms) { const s = Math.max(0, ms/1000|0), h = s/3600|0, m = (s%3600)/60|0;\n  return h ? `${h} h ${String(m).padStart(2,\"0\")}` : `${m} min`; }\nfunction sameDay(a, b) { return a.getFullYear()===b.getFullYear() && a.getMonth()===b.getMonth() && a.getDate()===b.getDate(); }\nfunction dayName(d) { return d.toLocaleDateString(\"fr-FR\", { weekday:\"long\", day:\"numeric\", month:\"short\" }); }\n\n// ---- Icônes (SVG inline)\nfunction arrow(up, cls) {\n  const c = up ? \"var(--high)\" : \"var(--low)\";\n  const path = up ? \"M12 19V5M6 11l6-6 6 6\" : \"M12 5v14M6 13l6 6 6-6\";\n  return `<svg class=\"${cls||''}\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"${c}\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"${path}\"/></svg>`;\n}\n\n// ---- Rendu\nfunction render() {\n  const now = new Date();\n  $(\"#portName\").textContent = state.port.nom;\n  $(\"#headSpin\").innerHTML = state.loading && state.tides.length ? '<div class=\"spinner\"></div>' : \"\";\n\n  if (state.error && !state.tides.length) {\n    $(\"#content\").innerHTML = `<div class=\"state\">\n      <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\"><path d=\"M2 8.8a15 15 0 0 1 20 0M5 12.5a10 10 0 0 1 14 0M8.5 16a5 5 0 0 1 7 0\"/><line x1=\"12\" y1=\"20\" x2=\"12\" y2=\"20\"/><line x1=\"3\" y1=\"3\" x2=\"21\" y2=\"21\"/></svg>\n      <div>${state.error}</div><button class=\"btn\" onclick=\"load()\">Réessayer</button></div>`;\n    return;\n  }\n  if (!state.tides.length) {\n    $(\"#content\").innerHTML = '<div class=\"state\"><div class=\"spinner\" style=\"margin:0 auto\"></div></div>';\n    return;\n  }\n\n  const t = state.tides;\n  const { next } = surrounding(now, t);\n  const h = heightNow(now, t);\n  const coef = coefNow(now, t);\n  const today = t.filter((x) => sameDay(x.date, now));\n\n  // Jours suivants (groupés)\n  const groups = {};\n  for (const x of t) { const k = new Date(x.date); k.setHours(0,0,0,0);\n    (groups[k.getTime()] ||= []).push(x); }\n  const keys = Object.keys(groups).map(Number).sort((a,b)=>a-b);\n  const upcoming = keys.slice(1, 6).map((k) => ({ day: new Date(k), tides: groups[k] }));\n\n  $(\"#content\").innerHTML = `\n    <section class=\"card hero\">\n      ${next ? `<div class=\"trend\">${isHigh(next)?'▲ Marée montante':'▼ Marée descendante'}</div>` : \"\"}\n      <div class=\"now-row\">\n        <div class=\"height\">${metres(h)}<small> m</small></div>\n        ${coef!=null ? `<div class=\"coef\"><b>${coef}</b><span>coef.</span></div>` : \"\"}\n      </div>\n      ${next ? `\n        <div class=\"divider\"></div>\n        <div class=\"next\">\n          ${arrow(isHigh(next),'ic')}\n          <div><div class=\"lbl\">Prochaine ${isHigh(next)?'pleine mer':'basse mer'}</div>\n          <div class=\"val\">${next.hhmm} · ${metres(next.hauteur)} m</div></div>\n          <div class=\"pill\">dans ${dur(next.date - now)}</div>\n        </div>` : \"\"}\n    </section>\n\n    <section class=\"card\"><h2>Hauteur d'eau</h2>${chartSVG(now, t)}</section>\n\n    <section class=\"card\"><h2>Aujourd'hui</h2>${today.map((x)=>rowHTML(x, now)).join(\"\")}</section>\n\n    ${upcoming.length ? `<section class=\"card\"><h2>Jours suivants</h2>\n      ${upcoming.map((g)=>`<div class=\"daygroup\"><div class=\"dayname\">${cap(dayName(g.day))}</div>\n        ${g.tides.map((x)=>rowHTML(x, now)).join(\"\")}</div>`).join(\"\")}\n    </section>` : \"\"}`;\n}\n\nfunction rowHTML(x, now) {\n  return `<div class=\"row ${x.date<now?'past':''}\">\n    ${arrow(isHigh(x),'ic')}\n    <span class=\"type\">${isHigh(x)?'Pleine mer':'Basse mer'}</span>\n    ${x.coef!=null?`<span class=\"rcoef\">${x.coef}</span>`:''}\n    <span class=\"h\">${metres(x.hauteur)} m</span>\n    <span class=\"t\">${x.hhmm}</span></div>`;\n}\nconst cap = (s) => s.charAt(0).toUpperCase() + s.slice(1);\n\n// ---- Courbe SVG (fenêtre -3h → +9h)\nfunction chartSVG(now, t) {\n  const W = 600, H = 200, padL = 4, padR = 4, padT = 24, padB = 22;\n  const start = new Date(now.getTime() - 3*3600e3), end = new Date(now.getTime() + 9*3600e3);\n  const pts = [];\n  for (let ms = start.getTime(); ms <= end.getTime(); ms += 600e3) {\n    const hv = heightNow(new Date(ms), t); if (hv != null) pts.push([ms, hv]);\n  }\n  if (pts.length < 2) return \"\";\n  const inWin = t.filter((x) => x.date >= start && x.date <= end);\n  const hs = pts.map((p)=>p[1]).concat(inWin.map((x)=>x.hauteur));\n  let lo = Math.min(...hs), hi = Math.max(...hs); const pad = (hi-lo)*0.15 || 1; lo -= pad; hi += pad;\n  const X = (ms) => padL + (ms - start) / (end - start) * (W - padL - padR);\n  const Y = (h) => padT + (1 - (h - lo)/(hi - lo)) * (H - padT - padB);\n\n  const line = pts.map((p,i)=>`${i?'L':'M'}${X(p[0]).toFixed(1)} ${Y(p[1]).toFixed(1)}`).join(\" \");\n  const area = `${line} L${X(pts[pts.length-1][0]).toFixed(1)} ${H-padB} L${X(pts[0][0]).toFixed(1)} ${H-padB} Z`;\n  const nx = X(now.getTime()), ny = Y(heightNow(now, t) ?? lo);\n\n  const dots = inWin.map((x)=>{\n    const cx = X(x.date.getTime()), cy = Y(x.hauteur);\n    const above = isHigh(x);\n    return `<circle cx=\"${cx.toFixed(1)}\" cy=\"${cy.toFixed(1)}\" r=\"3.2\" fill=\"#fff\"/>\n      <text x=\"${cx.toFixed(1)}\" y=\"${(above?cy-8:cy+16).toFixed(1)}\" fill=\"rgba(255,255,255,.85)\"\n        font-size=\"11\" font-weight=\"600\" text-anchor=\"middle\">${x.hhmm}</text>`;\n  }).join(\"\");\n\n  // Graduations horaires\n  const ticks = [];\n  const d0 = new Date(start); d0.setMinutes(0,0,0);\n  for (let ms = d0.getTime(); ms <= end.getTime(); ms += 3*3600e3) {\n    if (ms < start.getTime()) continue;\n    const hh = new Date(ms).toLocaleTimeString(\"fr-FR\",{hour:\"2-digit\",minute:\"2-digit\"});\n    ticks.push(`<text x=\"${X(ms).toFixed(1)}\" y=\"${H-6}\" fill=\"rgba(255,255,255,.55)\" font-size=\"10\" text-anchor=\"middle\">${hh}</text>`);\n  }\n\n  return `<svg class=\"chart\" viewBox=\"0 0 ${W} ${H}\" preserveAspectRatio=\"none\">\n    <defs><linearGradient id=\"fill\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n      <stop offset=\"0\" stop-color=\"#66d9ff\" stop-opacity=\".55\"/>\n      <stop offset=\"1\" stop-color=\"#0a6ab0\" stop-opacity=\"0\"/></linearGradient></defs>\n    <path d=\"${area}\" fill=\"url(#fill)\"/>\n    <path d=\"${line}\" fill=\"none\" stroke=\"#8fe3ff\" stroke-width=\"3\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/>\n    <line x1=\"${nx.toFixed(1)}\" y1=\"${padT-6}\" x2=\"${nx.toFixed(1)}\" y2=\"${H-padB}\" stroke=\"rgba(255,255,255,.55)\" stroke-width=\"1.4\" stroke-dasharray=\"4 4\"/>\n    <circle cx=\"${nx.toFixed(1)}\" cy=\"${ny.toFixed(1)}\" r=\"5\" fill=\"#fff\"/>\n    ${dots}${ticks.join(\"\")}\n  </svg>`;\n}\n\n// ---- Chargement\nasync function load() {\n  state.loading = true; state.error = null; render();\n  try {\n    state.tides = await apiTides(state.port.lat, state.port.lon);\n    if (!state.tides.length) state.error = \"Aucune donnée de marée pour ce port.\";\n  } catch (e) {\n    state.error = \"Impossible de charger les marées. Vérifie ta connexion.\";\n  }\n  state.loading = false; render();\n}\n\n// ---- Recherche\nlet searchTimer = null;\n$(\"#portBtn\").onclick = () => { $(\"#sheetBg\").classList.add(\"open\"); setTimeout(()=>$(\"#searchIn\").focus(), 50); };\n$(\"#sheetBg\").onclick = (e) => { if (e.target === $(\"#sheetBg\")) close(); };\nfunction close() { $(\"#sheetBg\").classList.remove(\"open\"); }\n$(\"#searchIn\").oninput = (e) => {\n  clearTimeout(searchTimer);\n  const q = e.target.value.trim();\n  if (q.length < 2) { $(\"#results\").innerHTML = \"\"; return; }\n  searchTimer = setTimeout(async () => {\n    $(\"#results\").innerHTML = '<div style=\"padding:14px;color:var(--faint)\">Recherche…</div>';\n    try {\n      const list = await apiSearch(q);\n      $(\"#results\").innerHTML = list.map((p, i) =>\n        `<button class=\"result\" data-i=\"${i}\">\n          <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"var(--high)\" stroke-width=\"2\" style=\"width:20px;height:20px;flex:0 0 20px\"><path d=\"M2 8.8a15 15 0 0 1 20 0M5 12.5a10 10 0 0 1 14 0M8.5 16a5 5 0 0 1 7 0\"/></svg>\n          <span>${p.nom}<small>${p.lat.toFixed(3)}, ${p.lon.toFixed(3)}</small></span></button>`\n      ).join(\"\") || '<div style=\"padding:14px;color:var(--faint)\">Aucun port trouvé.</div>';\n      Array.from(document.querySelectorAll(\".result\")).forEach((btn) => {\n        btn.onclick = () => {\n          const p = list[+btn.dataset.i];\n          state.port = { id: p.id, nom: p.nom, lat: p.lat, lon: p.lon, time_zone: p.time_zone };\n          savePort(state.port); close(); $(\"#searchIn\").value = \"\"; $(\"#results\").innerHTML = \"\";\n          state.tides = []; load();\n        };\n      });\n    } catch { $(\"#results\").innerHTML = '<div style=\"padding:14px;color:var(--faint)\">Recherche impossible.</div>'; }\n  }, 350);\n};\n\n// ---- Cycle de vie\nfunction startTick() { clearInterval(tick); tick = setInterval(render, 30000); }\ndocument.addEventListener(\"visibilitychange\", () => { if (!document.hidden) load(); });\nload(); startTick();\n\n// Service worker (mode hors-ligne léger)\nif (\"serviceWorker\" in navigator) navigator.serviceWorker.register(\"sw.js\").catch(()=>{});\n</script>\n</body>\n</html>\n","b64":false},"/manifest.webmanifest":{"type":"application/manifest+json","body":"{\n  \"name\": \"Marées\",\n  \"short_name\": \"Marées\",\n  \"description\": \"Horaires des marées, hauteur d'eau et coefficient pour les ports français.\",\n  \"lang\": \"fr\",\n  \"start_url\": \"./\",\n  \"scope\": \"./\",\n  \"display\": \"standalone\",\n  \"orientation\": \"portrait\",\n  \"background_color\": \"#04264c\",\n  \"theme_color\": \"#04264c\",\n  \"icons\": [\n    { \"src\": \"icon-180.png\", \"sizes\": \"180x180\", \"type\": \"image/png\" },\n    { \"src\": \"icon-512.png\", \"sizes\": \"512x512\", \"type\": \"image/png\", \"purpose\": \"any maskable\" },\n    { \"src\": \"icon-1024.png\", \"sizes\": \"1024x1024\", \"type\": \"image/png\" }\n  ]\n}\n","b64":false},"/sw.js":{"type":"text/javascript; charset=utf-8","body":"// Service worker minimal : coquille hors-ligne (app-shell), données toujours réseau.\nconst CACHE = \"maree-v1\";\nconst SHELL = [\"./\", \"./index.html\", \"./manifest.webmanifest\", \"./icon-180.png\", \"./icon-512.png\"];\n\nself.addEventListener(\"install\", (e) => {\n  e.waitUntil(caches.open(CACHE).then((c) => c.addAll(SHELL)).then(() => self.skipWaiting()));\n});\n\nself.addEventListener(\"activate\", (e) => {\n  e.waitUntil(\n    caches.keys().then((keys) => Promise.all(keys.filter((k) => k !== CACHE).map((k) => caches.delete(k))))\n      .then(() => self.clients.claim())\n  );\n});\n\nself.addEventListener(\"fetch\", (e) => {\n  const url = new URL(e.request.url);\n  // Les appels API passent toujours par le réseau (jamais de cache).\n  if (url.pathname.startsWith(\"/api/\")) return;\n  // App-shell : réseau d'abord, repli sur le cache hors-ligne.\n  e.respondWith(\n    fetch(e.request).then((r) => {\n      if (e.request.method === \"GET\" && r.ok) {\n        const clone = r.clone();\n        caches.open(CACHE).then((c) => c.put(e.request, clone));\n      }\n      return r;\n    }).catch(() => caches.match(e.request).then((m) => m || caches.match(\"./index.html\")))\n  );\n});\n","b64":false},"/icon-180.png":{"type":"image/png","body":"","b64":true},"/icon-512.png":{"type":"image/png","body":"","b64":true},"/icon-1024.png":{"type":"image/png","body":"","b64":true}};

const MC_SEARCH = "https://ws.meteoconsult.fr/meteoconsultmarine/android/100/fr/v30/recherche.php";
const MC_SPOT = "https://ws.meteoconsult.fr/meteoconsultmarine/androidtab/115/fr/v30/previsionsSpot.php";
const UA = "Mozilla/5.0 (Linux; Android 10) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/146.0.0.0 Mobile Safari/537.36";

function decodeB64(b64) {
  const bin = atob(b64); const arr = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
  return arr;
}

async function proxy(upstream) {
  const r = await fetch(upstream, { headers: { "User-Agent": UA, "Accept": "application/json" } });
  const body = await r.text();
  return new Response(body, {
    status: r.status,
    headers: {
      "content-type": "application/json; charset=utf-8",
      "access-control-allow-origin": "*",
      "cache-control": "public, max-age=300",
    },
  });
}

export default {
  async fetch(request) {
    const url = new URL(request.url);
    const path = url.pathname;

    // API : recherche de ports
    if (path === "/api/search") {
      const q = url.searchParams.get("q") || "";
      return proxy(MC_SEARCH + "?rech=" + encodeURIComponent(q));
    }
    // API : prévisions de marées
    if (path === "/api/tides") {
      const lat = url.searchParams.get("lat"), lon = url.searchParams.get("lon");
      return proxy(MC_SPOT + "?lat=" + encodeURIComponent(lat) + "&lon=" + encodeURIComponent(lon));
    }

    // Assets statiques (index à la racine)
    const key = path === "/" ? "/index.html" : path;
    const a = ASSETS[key];
    if (a) {
      const body = a.b64 ? decodeB64(a.body) : a.body;
      return new Response(body, {
        headers: { "content-type": a.type, "cache-control": "public, max-age=3600" },
      });
    }
    return new Response("Not found", { status: 404 });
  },
};
